  // Onboarding (additional)
  'onboarding.subtitle': { fr: 'Défie des joueurs du monde entier\nsur des milliers de questions', en: 'Challenge players from around the world\non thousands of questions', es: 'Desafía a jugadores de todo el mundo\nen miles de preguntas', de: 'Fordere Spieler aus aller Welt heraus\nbei tausenden Fragen', pt: 'Desafie jogadores do mundo inteiro\nem milhares de perguntas', it: 'Sfida giocatori da tutto il mondo\nsu migliaia di domande', ar: 'تحدى لاعبين من جميع أنحاء العالم\nفي آلاف الأسئلة', ja: '世界中のプレイヤーに挑戦しよう\n何千もの問題で', ko: '전 세계 플레이어에게 도전하세요\n수천 개의 문제로', zh: '挑战来自世界各地的玩家\n数千道题目' },
