  'onboarding.tuto_title_1': { fr: 'Trouve un adversaire', en: 'Find an opponent', es: 'Encuentra un adversario', de: 'Finde einen Gegner', pt: 'Encontre um adversário', it: 'Trova un avversario', ar: 'اعثر على خصم', ja: '対戦相手を見つけよう', ko: '상대를 찾으세요', zh: '找到对手' },
  'onboarding.tuto_body_1': { fr: 'Choisis un thème et lance une recherche.\nTu seras matché avec un joueur de ton niveau.', en: 'Choose a theme and start a search.\nYou will be matched with a player at your level.', es: 'Elige un tema e inicia una búsqueda.\nSerás emparejado con un jugador de tu nivel.', de: 'Wähle ein Thema und starte eine Suche.\nDu wirst mit einem Spieler deines Niveaus gematcht.', pt: 'Escolha um tema e inicie uma busca.\nVocê será pareado com um jogador do seu nível.', it: 'Scegli un tema e avvia una ricerca.\nSarai abbinato a un giocatore del tuo livello.', ar: 'اختر موضوعًا وابدأ البحث.\nسيتم مطابقتك مع لاعب من مستواك.', ja: 'テーマを選んで検索を開始。\nあなたのレベルに合ったプレイヤーとマッチします。', ko: '테마를 선택하고 검색을 시작하세요.\n당신의 레벨에 맞는 플레이어와 매칭됩니다.', zh: '选择一个主题并开始搜索。\n你将与同水平的玩家匹配。' },
  'onboarding.tuto_title_2': { fr: '7 questions, 10 secondes', en: '7 questions, 10 seconds', es: '7 preguntas, 10 segundos', de: '7 Fragen, 10 Sekunden', pt: '7 perguntas, 10 segundos', it: '7 domande, 10 secondi', ar: '7 أسئلة، 10 ثوانٍ', ja: '7問、10秒', ko: '7문제, 10초', zh: '7个问题，10秒' },
  'onboarding.tuto_body_2': { fr: 'Réponds vite et bien !\nChaque bonne réponse rapide donne plus de points.', en: 'Answer quickly and correctly!\nEach fast correct answer gives more points.', es: '¡Responde rápido y bien!\nCada respuesta correcta rápida da más puntos.', de: 'Antworte schnell und richtig!\nJede schnelle richtige Antwort gibt mehr Punkte.', pt: 'Responda rápido e bem!\nCada resposta correta rápida dá mais pontos.', it: 'Rispondi velocemente e bene!\nOgni risposta corretta veloce dà più punti.', ar: 'أجب بسرعة وبشكل صحيح!\nكل إجابة صحيحة سريعة تمنح المزيد من النقاط.', ja: '素早く正確に答えよう！\n早い正解ほどポイントが高い。', ko: '빠르고 정확하게 답하세요!\n빠른 정답일수록 더 많은 점수를 얻습니다.', zh: '快速准确地回答！\n每个快速正确的答案可获得更多分数。' },
  'onboarding.tuto_title_3': { fr: 'Progresse et grimpe', en: 'Progress and climb', es: 'Progresa y sube', de: 'Fortschritt und aufsteigen', pt: 'Progrida e suba', it: 'Progredisci e scala', ar: 'تقدم وارتقِ', ja: '成長してランクアップ', ko: '성장하고 올라가세요', zh: '进步并攀升' },
  'onboarding.tuto_body_3': { fr: "Gagne de l'XP, débloque des titres\net monte dans le classement mondial.", en: 'Earn XP, unlock titles\nand climb the global leaderboard.', es: 'Gana XP, desbloquea títulos\ny sube en la clasificación mundial.', de: 'Verdiene XP, schalte Titel frei\nund steige in der Weltrangliste auf.', pt: 'Ganhe XP, desbloqueie títulos\ne suba no ranking mundial.', it: "Guadagna XP, sblocca titoli\ne scala la classifica mondiale.", ar: 'اكسب نقاط خبرة، افتح ألقابًا\nوارتقِ في التصنيف العالمي.', ja: 'XPを獲得し、称号をアンロックし\n世界ランキングを上げよう。', ko: 'XP를 획득하고, 칭호를 해제하고\n세계 순위에서 올라가세요.', zh: '赚取经验值，解锁称号\n并登上全球排行榜。' },

